verificationEvidence.command:
try { $r = Invoke-WebRequest -Uri "http://balaidiklat.test/" -TimeoutSec 90 -UseBasicParsing; $c = $r.Content; $checks = @(
  @{Name="Form Pemesanan"; Pattern="FORM_PEMESANAN_LANDING"},
  @{Name="Maps iframe"; Pattern="Fatmawati"},
  @{Name="WA Bot Number"; Pattern="62878455351641"},
  @{Name="Cek Ketersediaan"; Pattern="cek-ketersediaan"},
  @{Name="jenis_kelas usage"; Pattern="jenis_kelas"}
); foreach ($check in $checks) { $found = $c -match $check.Pattern; Write-Output "$($check.Name): $(if ($found) {'OK'} else {'MISSING'})" } } catch { Write-Output "ERROR: $_" }

